    console.log(JSON.stringify({
      timestamp: new Date().toISOString(),
      level: 'INFO',
      message,
      ...data,
      cpfMasked: data.cpf ? maskCpf(data.cpf) : undefined,
      cpf: undefined // Never log raw CPF
    }));
  }
};
